/// User interaction logger: taps, navigation, input changes.
class UserInteractionLogger extends NavigatorObserver {
  UserInteractionLogger({ProdLogger? logger}) : _log = logger ?? ProdLogger.I;

  final ProdLogger _log;

  void logTap(String name, {Map<String, Object?>? props}) {
    _log.info('UI tap', fields: {'name': name, if (props != null) ...props});
  }

  void logLongPress(String name, {Map<String, Object?>? props}) {
    _log.info('UI longPress', fields: {'name': name, if (props != null) ...props});
  }

  void logInput(String fieldName, String value, {Map<String, Object?>? props}) {
    _log.debug('UI input', fields: {'field': fieldName, 'value': value, if (props != null) ...props});
  }

  void logEvent(String name, {Map<String, Object?>? props}) {
    _log.info('UI event', fields: {'name': name, if (props != null) ...props});
  }

  @override
  void didPush(Route<dynamic> route, Route<dynamic>? previousRoute) {
    _log.info('Navigation push', fields: {'to': _routeName(route), 'from': previousRoute != null ? _routeName(previousRoute) : null});
    super.didPush(route, previousRoute);
  }

  @override
  void didPop(Route<dynamic> route, Route<dynamic>? previousRoute) {
    _log.info('Navigation pop', fields: {'from': _routeName(route), 'to': previousRoute != null ? _routeName(previousRoute) : null});
    super.didPop(route, previousRoute);
  }

  @override
  void didReplace({Route<dynamic>? newRoute, Route<dynamic>? oldRoute}) {
    _log.info('Navigation replace', fields: {'new': newRoute != null ? _routeName(newRoute) : null, 'old': oldRoute != null ? _routeName(oldRoute) : null});
    super.didReplace(newRoute: newRoute, oldRoute: oldRoute);
  }

  String _routeName(Route<dynamic> route) {
    final settingsName = route.settings.name;
    if (settingsName != null && settingsName.isNotEmpty) return settingsName;
    return route.runtimeType.toString();
  }
}

/// Widget helper to log taps without wiring GestureDetector everywhere.
class LogTap extends StatelessWidget {
  const LogTap({
    super.key,
    required this.name,
    required this.child,
    this.onTap,
    this.props,
    this.logger,
    this.behavior,
  });

  final String name;
  final Widget child;
  final VoidCallback? onTap;
  final Map<String, Object?>? props;
  final UserInteractionLogger? logger;
  final HitTestBehavior? behavior;

  @override
  Widget build(BuildContext context) {
    final l = logger ?? _findLogger(context) ?? UserInteractionLogger();
    return GestureDetector(
      behavior: behavior ?? HitTestBehavior.opaque,
      onTap: () {
        l.logTap(name, props: props);
        onTap?.call();
      },
      child: child,
    );
  }

  UserInteractionLogger? _findLogger(BuildContext context) {
    final nav = Navigator.of(context);
    for (final o in nav.widget.observers) {
      if (o is UserInteractionLogger) return o;
    }
    return null;
  }
}

/// Global error hooks for Flutter framework and platform dispatcher.
class AppHealthMonitor {
  AppHealthMonitor({ProdLogger? logger}) : _log = logger ?? ProdLogger.I;

  final ProdLogger _log;

  void install() {
    FlutterError.onError = (FlutterErrorDetails details) {
      _log.error(
        'Flutter framework error',
        fields: {
          'library': details.library,
          'context': details.context?.toDescription(),
          'information': details.informationCollector?.call().map((n) => n.toString()).toList(),
        },
        error: details.exception,
        stackTrace: details.stack,
      );
    };

    PlatformDispatcher.instance.onError = (error, stack) {
      _log.error('Uncaught platform error', error: error, stackTrace: stack);
      return true;
    };

    _log.info('AppHealthMonitor installed', fields: {'releaseMode': kReleaseMode, 'platform': Platform.operatingSystem});
  }
}

