  static void configure({
    bool enabled = true,
    bool logSecrets = false,
    int maxPayloadChars = 4096,
    int maxBodyBytes = 65536,
    int maxLinesPerSecond = 50,
  }) {
    final l = ProdLogger.I;
    l.enabled = enabled;
    l.logSecrets = logSecrets;
    l.maxPayloadChars = maxPayloadChars;
    l.maxBodyBytes = maxBodyBytes;
    l.maxLinesPerSecond = maxLinesPerSecond;
  }

  static LoggingHttpClient httpClient({http.Client? inner}) => LoggingHttpClient(inner: inner, logger: ProdLogger.I);

  static LoggingDatabase database() => LoggingDatabase(logger: ProdLogger.I);

  static AuthLogger auth() => AuthLogger(logger: ProdLogger.I);

  static UserInteractionLogger uiObserver() => UserInteractionLogger(logger: ProdLogger.I);

  static AppHealthMonitor health() => AppHealthMonitor(logger: ProdLogger.I);
}